#include <stdio.h>
#include <stdlib.h>

int main() {
    FILE *fp;
    char note[100];

    // 1. Write (Append mode)
    fp = fopen("diary.txt", "a");
    if (fp == NULL) {
        printf("Error!\n");
        return 1;
    }

    printf("Enter a note to save: ");
    fgets(note, sizeof(note), stdin);

    fprintf(fp, "Entry: %s", note);
    printf("Saved!\n");

    fclose(fp);

    // 2. Read back
    printf("\n--- Reading Log ---\n");
    fp = fopen("diary.txt", "r");

    char buffer[100];
    while(fgets(buffer, 100, fp) != NULL) {
        printf("%s", buffer);
    }

    fclose(fp);
    return 0;
}
